import re
# Quick check of 2L credit agreement for financial covenant and call premium via the read-extracted text isn't possible via grep on docx.
# Instead use python-docx to extract text and search.
try:
    from docx import Document
    d = Document('documents/second-lien-credit-agreement.docx')
    text = '\n'.join(p.text for p in d.paragraphs)
    # search for key terms
    for kw in ['6.5', 'Total Leverage', '6.50', 'call premium', '102%', '101%', 'make-whole', 'Make-Whole', 'soft call', '102', '101', 'Total Net Leverage', 'financial maintenance', 'Financial Maintenance']:
        idxs = [m.start() for m in re.finditer(re.escape(kw), text)]
        if idxs:
            print(f'--- KW: {kw!r} ({len(idxs)} hits) ---')
            for i in idxs[:3]:
                print('   ...'+text[max(0,i-120):i+160].replace(chr(10),' ')+'...')
except Exception as e:
    print('ERR', e)
""}

